#!/usr/bin/env python3
"""
Bug #0033: jax.jit produces wrong output vs jax.disable_jit.

Patterns    : [['constant', 'identity_chain_two'], ['fusion', 'conv_tanh_head'], ['layout', 'slice_pad_concat'], ['broadcast', 'floor_unary'], ['broadcast', 'ceil_unary'], ['attention', 'matmul_4d_batch']]
Dependencies: numpy jax
Run         : python unique_0033.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64, 3, 1, 1])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w2 = np.frombuffer(bytes.fromhex("00000000000000000000000000000000"), dtype=np.float32).reshape([4])
_w3 = np.frombuffer(bytes.fromhex("0000803f000080420000804100000042"), dtype=np.float32).reshape([4])
_w4 = np.frombuffer(bytes.fromhex("0000000000000000000000000000000000000000000000000000804100000000"), dtype=np.float32).reshape([8])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 32, 32])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 32, 32])  # input "model_input"


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_ic2_i1 = x
    n0_ic2_out = n0_ic2_i1
    n100_cth_cv = (lax.conv_general_dilated(n0_ic2_out, _w0, window_strides=[1, 1], padding=((0, 0), (0, 0)), lhs_dilation=(1,1), rhs_dilation=[1, 1], dimension_numbers=('NCHW','OIHW','NCHW'), feature_group_count=1) + jnp.reshape(_w1, [1,-1,1,1]))
    n100_cth_out = jnp.tanh(n100_cth_cv)
    n200_spc_sl = (lambda _x, _s, _e, _ax, _st: _x[tuple(slice(int(_s[k]),int(_e[k]) if abs(int(_e[k]))<2**30 else None,int(_st[k])) if k < len(_ax) else slice(None) for k in range(len(_x.shape)))])(n100_cth_out, _w2, _w3, np.arange(len(n100_cth_out.shape)), np.ones(len(_w2), dtype=np.int64))
    n200_spc_pd = jnp.pad(n200_spc_sl, [(int(_w4[k]), int(_w4[k+len(n200_spc_sl.shape)])) for k in range(len(n200_spc_sl.shape))], mode='constant')
    n200_spc_out = jnp.concatenate([n100_cth_out, n200_spc_pd], axis=1)
    n300_floo_a = jnp.floor(n200_spc_out)
    n300_floo_out = n300_floo_a * n200_spc_out
    n400_ceil_a = jnp.ceil(n300_floo_out)
    n400_ceil_out = n400_ceil_a * n300_floo_out
    n500_mm4d_out = jnp.matmul(n400_ceil_out, _w5)
    return jnp.asarray(n500_mm4d_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)

    with jax.disable_jit():
        ref = np.array(model(x_jax), dtype=np.float32).ravel()

    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(ref.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(ref.astype(np.float64)) + 1e-8))
    print(f"expected (jax.disable_jit): {ref[:6]}")
    print(f"actual   (jax.jit)        : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
